## 3. Step-by-Step Algorithm & Analytical Matrix

### 3.1 Complete C Program (KTU 2024 Standard)

```c
#include <stdio.h>
#include <stdlib.h>

/* ---------- Node Definition ---------- */
struct Node {
    int coeff;        // Coefficient of the term
    int expo;         // Exponent (power) of the term
    struct Node *next; // Pointer to the next node
};

/* ---------- Function Prototypes ---------- */
struct Node* createNode(int c, int e);
struct Node* insertEnd(struct Node *head, int c, int e);
struct Node* createPolynomial(void);
void display(struct Node *head);
struct Node* addPolynomials(struct Node *p1, struct Node *p2);
void freeList(struct Node *head);

/* ---------- Create a Single Node ---------- */
struct Node* createNode(int c, int e) {
    struct Node *newNode = (struct Node*)malloc(sizeof(struct Node));
    if (newNode == NULL) {
        printf("Memory allocation failed!\n");
        exit(1);
    }
    newNode->coeff = c;
    newNode->expo  = e;
    newNode->next  = NULL;
    return newNode;
}

/* ---------- Insert a Term at the End ---------- */
struct Node* insertEnd(struct Node *head, int c, int e) {
    struct Node *newNode = createNode(c, e);
    if (head == NULL) return newNode;
    struct Node *temp = head;
    while (temp->next != NULL) temp = temp->next;
    temp->next = newNode;
    return head;
}

/* ---------- Read Polynomial from User ---------- */
struct Node* createPolynomial(void) {
    struct Node *head = NULL;
    int n, c, e, i;
    printf("\nEnter the number of terms: ");
    scanf("%d", &n);
    for (i = 0; i < n; i++) {
        printf("  Term %d -> Enter coefficient and exponent: ", i + 1);
        scanf("%d %d", &c, &e);
        head = insertEnd(head, c, e);
    }
    return head;
}

/* ---------- Display Polynomial ---------- */
void display(struct Node *head) {
    if (head == NULL) { printf("0"); return; }
    struct Node *temp = head;
    while (temp != NULL) {
        if (temp->coeff != 0) {
            if (temp != head && temp->coeff > 0) printf(" + ");
            else if (temp->coeff < 0) printf(" - ");
            if (temp->expo == 0)        printf("%d", abs(temp->coeff));
            else if (temp->expo == 1)   printf("%dx", abs(temp->coeff));
            else                        printf("%dx^%d", abs(temp->coeff), temp->expo);
        }
        temp = temp->next;
    }
}

/* ---------- Core Algorithm: Polynomial Addition ---------- */
struct Node* addPolynomials(struct Node *p1, struct Node *p2) {
    struct Node *result = NULL, *tail = NULL;
    while (p1 != NULL && p2 != NULL) {
        int c, e;
        if (p1->expo == p2->expo) {
            c = p1->coeff + p2->coeff;
            e = p1->expo;
            p1 = p1->next;
            p2 = p2->next;
            if (c == 0) continue;            /* Skip zero-result terms */
        } else if (p1->expo > p2->expo) {
            c = p1->coeff;  e = p1->expo;  p1 = p1->next;
        } else {
            c = p2->coeff;  e = p2->expo;  p2 = p2->next;
        }
        /* Append (c, e) to the result list */
        struct Node *newNode = createNode(c, e);
        if (result == NULL) { result = tail = newNode; }
        else { tail->next = newNode; tail = newNode; }
    }
    /* Append remaining terms */
    while (p1 != NULL) { result = insertEnd(result, p1->coeff, p1->expo); p1 = p1->next; }
    while (p2 != NULL) { result = insertEnd(result, p2->coeff, p2->expo); p2 = p2->next; }
    return result;
}

/* ---------- Free Memory ---------- */
void freeList(struct Node *head) {
    struct Node *tmp;
    while (head != NULL) { tmp = head; head = head->next; free(tmp); }
}

/* ---------- Main Driver ---------- */
int main(void) {
    struct Node *poly1, *poly2, *sum;
    printf("=== Create First Polynomial P1(x) ===");
    poly1 = createPolynomial();
    printf("\n=== Create Second Polynomial P2(x) ===");
    poly2 = createPolynomial();

    printf("\nP1(x) = "); display(poly1);
    printf("\nP2(x) = "); display(poly2);

    sum = addPolynomials(poly1, poly2);
    printf("\n\nP1(x) + P2(x) = "); display(sum);
    printf("\n");

    freeList(poly1); freeList(poly2); freeList(sum);
    return 0;
}
```

### 3.2 Worked-Out Analytical Trace

Let us trace the algorithm with a concrete example to make the logic unambiguous.

**Input**:
$$P_1(x) = 5x^3 + 4x^2 + 2$$
$$P_2(x) = 3x^3 + 2x + 1$$

**Linked list structures**:

| Pointer | `p1->expo` | `p1->coeff` | `p2->expo` | `p2->coeff` |
|---|---|---|---|---|
| Start | 3 | 5 | 3 | 3 |

#### Iteration-by-iteration trace of `addPolynomials`

| Step | `p1->expo` | `p2->expo` | Comparison | Action | `c` | `e` | Result List So Far |
|---|---|---|---|---|---|---|---|
| 1 | 3 | 3 | Equal | $c = 5 + 3$ | 8 | 3 | $8x^3$ |
| 2 | 2 | 2 | `p1> p2` (in `p2`, exponent is now 1) | Copy P₁ | 4 | 2 | $8x^3 + 4x^2$ |
| 3 | 0 | 1 | `p1< p2` (in P₁ exponent is 0, in P₂ it is 1) | Copy P₂ | 2 | 1 | $8x^3 + 4x^2 + 2x$ |
| 4 | 0 | 0 | Equal | $c = 2 + 1$ | 3 | 0 | $8x^3 + 4x^2 + 2x + 3$ |
| 5 | NULL | — | P₁ exhausted | Copy remaining of P₂ | — | — | (none) |

**Final output**:
$$P_1(x) + P_2(x) = 8x^3 + 4x^2 + 2x + 3$$

> [!IMPORTANT]
> **Cross-check by hand**: $(5x^3 + 4x^2 + 2) + (3x^3 + 2x + 1) = 8x^3 + 4x^2 + 2x + 3$. ✓ The linked list algorithm correctly merges the polynomials in **a single pass** with complexity $O(n + m)$.

