## 3.2 PROGRAM 2 — Binary Search Tree (Dictionary / Phonebook)

### 3.2.1 Complete Working C Program (KTU Lab Standard)

```c
/* ======================================================
   KTU PCITL308 - Module Experiment 2
   Application: BST as Dictionary (insert, search, delete, display)
   ====================================================== */
#include <stdio.h>
#include <stdlib.h>
#include <string.h>

struct Node {
    int   key;
    char  name[40];
    struct Node *left, *right;
};

/* ---------- Create node ---------- */
struct Node* newNode(int key, char *name) {
    struct Node* n = (struct Node*)malloc(sizeof(struct Node));
    n->key = key;
    strcpy(n->name, name);
    n->left = n->right = NULL;
    return n;
}

/* ---------- Insert (recursive) ---------- */
struct Node* insert(struct Node* r, int key, char *name) {
    if (r == NULL) return newNode(key, name);
    if (key < r->key) r->left  = insert(r->left,  key, name);
    else if (key > r->key) r->right = insert(r->right, key, name);
    else printf("Duplicate key %d ignored.\n", key);
    return r;
}

/* ---------- Search (iterative) ---------- */
struct Node* search(struct Node* r, int key) {
    while (r != NULL) {
        if (key == r->key)   return r;
        else if (key < r->key) r = r->left;
        else                    r = r->right;
    }
    return NULL;
}

/* ---------- Find minimum (leftmost) ---------- */
struct Node* findMin(struct Node* r) {
    while (r && r->left != NULL) r = r->left;
    return r;
}

/* ---------- Delete node ---------- */
struct Node* deleteNode(struct Node* r, int key) {
    if (r == NULL) return r;
    if (key < r->key)      r->left  = deleteNode(r->left,  key);
    else if (key > r->key) r->right = deleteNode(r->right, key);
    else {
        /* Case 1 & 2: zero or one child */
        if (r->left == NULL) { struct Node* t = r->right; free(r); return t; }
        if (r->right == NULL){ struct Node* t = r->left;  free(r); return t; }
        /* Case 3: two children — replace with inorder successor */
        struct Node* succ = findMin(r->right);
        r->key  = succ->key;
        strcpy(r->name, succ->name);
        r->right = deleteNode(r->right, succ->key);
    }
    return r;
}

/* ---------- Traversals ---------- */
void inorder(struct Node* r) {
    if (r == NULL) return;
    inorder(r->left);
    printf("[%d : %s]\n", r->key, r->name);
    inorder(r->right);
}
void preorder(struct Node* r) {
    if (!r) return;
    printf("[%d : %s]\n", r->key, r->name);
    preorder(r->left);
    preorder(r->right);
}
void postorder(struct Node* r) {
    if (!r) return;
    postorder(r->left);
    postorder(r->right);
    printf("[%d : %s]\n", r->key, r->name);
}

/* ---------- Free tree ---------- */
void freeTree(struct Node* r) {
    if (!r) return;
    freeTree(r->left);
    freeTree(r->right);
    free(r);
}

/* ---------- Menu ---------- */
int main(void) {
    struct Node *root = NULL, *res;
    int  choice, key;
    char name[40];

    while (1) {
        printf("\n--- BST DICTIONARY MENU ---\n");
        printf("1.Insert  2.Search  3.Delete  4.Inorder\n");
        printf("5.Preorder 6.Postorder  7.Exit\nChoice: ");
        if (scanf("%d", &choice) != 1) break;

        switch (choice) {
            case 1:
                printf("Enter key and name: ");
                scanf("%d %s", &key, name);
                root = insert(root, key, name);
                break;
            case 2:
                printf("Enter key to search: ");
                scanf("%d", &key);
                res = search(root, key);
                if (res) printf("Found: [%d : %s]\n", res->key, res->name);
                else     printf("Key %d not found.\n", key);
                break;
            case 3:
                printf("Enter key to delete: ");
                scanf("%d", &key);
                root = deleteNode(root, key);
                break;
            case 4: inorder(root);   break;
            case 5: preorder(root);  break;
            case 6: postorder(root); break;
            case 7: freeTree(root); return 0;
            default: printf("Invalid choice.\n");
        }
    }
    return 0;
}
```

### 3.2.2 Derivation of the Three Delete Cases

For a node to be deleted, three structural situations can occur:

**Case 1 — Leaf node (no children):** Simply free the node and return `NULL` to its parent.
$$\text{delete}(N_{\text{leaf}}) = \text{free}(N) \rightarrow \text{NULL}$$

**Case 2 — One child:** Bypass the node by returning its only child to the parent.
$$\text{delete}(N) = N.\text{right} \quad \text{if } N.\text{left} = \text{NULL}$$
$$\text{delete}(N) = N.\text{left} \quad \text{if } N.\text{right} = \text{NULL}$$

**Case 3 — Two children (most tested in KTU):**
1. Find the **inorder successor** $S$ = minimum node in right subtree.
2. **Copy** $S$'s data into $N$.
3. **Recursively delete** $S$ from the right subtree.

This preserves the BST property because $S$ is the smallest key greater than $N.\text{key}$, and removing it from the right subtree leaves the BST invariant intact.

